import{_ as i,I as a,g as s,j as t}from"./chunks/framework.CbuNJfvM.js";const g=JSON.parse('{"title":"tooling","description":"","frontmatter":{},"headers":[],"relativePath":"tooling.md","filePath":"tooling.md"}'),n={name:"tooling.md"};function l(o,e,r,h,p,d){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="tooling" tabindex="-1">tooling <a class="header-anchor" href="#tooling" aria-label="Permalink to &quot;tooling&quot;">​</a></h1><p>The ghūl compiler is a .NET tool, and ghūl projects are ordinary .NET SDK projects. This means most of the tooling you already use for .NET applies directly, with a language extension on top for editing.</p><h2 id="the-compiler" tabindex="-1">the compiler <a class="header-anchor" href="#the-compiler" aria-label="Permalink to &quot;the compiler&quot;">​</a></h2><p>The compiler is published as the <a href="https://www.nuget.org/packages/ghul.compiler" target="_blank" rel="noreferrer"><code class="ghul-inline-plain">ghul.compiler</code></a> .NET tool. Once installed it is invoked as <code class="ghul-inline"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> ghul-compiler</span></code>.</p><p>You don&#39;t usually run the compiler by hand. ghūl projects are built with MSBuild through a <code class="ghul-inline-plain">.ghulproj</code> project file, and the <code class="ghul-inline-plain">ghul.runtime</code> package supplies the MSBuild targets that drive the compiler for you. See <a href="/getting-started.html">getting started</a> for installing the compiler and setting up a project.</p><p>The compiler is normally installed as a <em>local</em> .NET tool, pinned per project in <code class="ghul-inline-plain">.config/dotnet-tools.json</code>, so everyone building the project uses the same compiler version. <code class="ghul-inline"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> tool</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> restore</span></code> restores it.</p><h2 id="building-and-running" tabindex="-1">building and running <a class="header-anchor" href="#building-and-running" aria-label="Permalink to &quot;building and running&quot;">​</a></h2><p>Because a ghūl project is a normal .NET SDK project, the standard <code class="ghul-inline-plain">dotnet</code> commands all work:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> build</span><span style="--shiki-light:#008000;--shiki-dark:#6A9955;">   # compile the project</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> run</span><span style="--shiki-light:#008000;--shiki-dark:#6A9955;">     # build and run an executable project</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> pack</span><span style="--shiki-light:#008000;--shiki-dark:#6A9955;">    # produce a NuGet package</span></span>
<span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> test</span><span style="--shiki-light:#008000;--shiki-dark:#6A9955;">    # run a test project</span></span></code></pre></div><p>A ghūl project can reference NuGet packages, produce libraries or executables, and be packed and published exactly like a C# project.</p><h2 id="the-visual-studio-code-extension" tabindex="-1">the Visual Studio Code extension <a class="header-anchor" href="#the-visual-studio-code-extension" aria-label="Permalink to &quot;the Visual Studio Code extension&quot;">​</a></h2><p>The <a href="https://marketplace.visualstudio.com/items?itemName=degory.ghul" target="_blank" rel="noreferrer">ghūl language extension</a> provides rich language support while you edit:</p><ul><li>errors and warnings reported as you type</li><li>code completion</li><li>hover information</li><li>go to definition and find references</li><li>rename</li><li>signature help</li><li>source code formatting</li></ul><p>Behind the scenes the extension runs the ghūl compiler in its analysis mode: the compiler stays resident, maintains an up-to-date analysis of your project, and updates it as you edit, reporting diagnostics back into the editor.</p><p>On large projects the extension updates this analysis in two stages — a quick partial pass over the file you are editing, followed by a full pass once you pause. This is usually invisible, though it does mean a diagnostic can occasionally appear or disappear a moment after an edit.</p><h2 id="dev-containers" tabindex="-1">dev containers <a class="header-anchor" href="#dev-containers" aria-label="Permalink to &quot;dev containers&quot;">​</a></h2><p>The ghūl repository template and the examples repo both ship a <code class="ghul-inline"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">devcontainer</span></code> configured to use a standard .NET 10 dev container image - for example <a href="https://hub.docker.com/r/microsoft/devcontainers-dotnet" target="_blank" rel="noreferrer"><code class="ghul-inline"><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">mcr</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">microsoft</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">.</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">com</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">/</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">devcontainers</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">/</span><span style="--shiki-light:#001080;--shiki-dark:#9CDCFE;">dotnet</span><span style="--shiki-light:#0000FF;--shiki-dark:#569CD6;">:</span><span style="--shiki-light:#098658;--shiki-dark:#B5CEA8;">10.0</span></code></a>. Open the project in VS Code with the Dev Containers extension, or in a GitHub Codespace, and <code class="ghul-inline"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> tool</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> restore</span></code> will install the compiler from the local tool manifest. Any image with the .NET 10 SDK and <code class="ghul-inline-plain">dotnet</code> on the PATH will work.</p><h2 id="project-templates" tabindex="-1">project templates <a class="header-anchor" href="#project-templates" aria-label="Permalink to &quot;project templates&quot;">​</a></h2><p>The <a href="https://www.nuget.org/packages/ghul.templates" target="_blank" rel="noreferrer"><code class="ghul-inline-plain">ghul.templates</code></a> package adds ghūl project templates to the .NET SDK:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes light-plus dark-plus vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> new</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> install</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> ghul.templates</span></span></code></pre></div><p>Once installed, <code class="ghul-inline"><span style="--shiki-light:#795E26;--shiki-dark:#DCDCAA;">dotnet</span><span style="--shiki-light:#A31515;--shiki-dark:#CE9178;"> new</span></code> can scaffold a ghūl project pre-configured with a <code class="ghul-inline-plain">.ghulproj</code>, the compiler pinned as a local tool, and a starting source file. See <a href="/getting-started.html">getting started</a> for the other ways to get a project off the ground.</p>`,21)])])}const k=i(n,[["render",l]]);export{g as __pageData,k as default};
